INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 0, 20001, 10, 319, "", "", 0, 24016, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (20, 2, 0, 20001, 10, 320, "", "", 0, 23001, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 0, 40011, 1, 321, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", "リリ", 1, 24001, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 0, 40011, 2, 322, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", "クリア", 1, 24001, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 0, 40011, 3, 323, "んーと。\nこれ、あげる。\nはい", "プレシア", 1, 24001, 126101);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 0, 40011, 4, 324, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", "リリ", 2, 24001, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 0, 40011, 5, 325, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", "クリア", 2, 24001, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 0, 40011, 6, 326, "お兄。\nきてくれて、うれしい", "プレシア", 2, 24001, 126101);
